from django.conf import settings
from django.contrib.auth import authenticate, login
from django.http import HttpResponseRedirect
from django.shortcuts import render
from django.views.decorators.csrf import csrf_exempt
from saml2 import BINDING_HTTP_POST, config
from saml2.client import Saml2Client
from saml2.response import AuthnResponse

# Prevent SAML timestamp validation
config.VALIDATE_TIMESTAMP = False

@csrf_exempt
def saml_acs(request):
    # Initialize the SAML client
    client = Saml2Client(config.CONFIG)

    # Parse the SAML response
    authn_response = AuthnResponse(client, request.POST['SAMLResponse'])

    # Extract user information from assertion attributes
    name_id = authn_response.ava['NameID'][0]
    email = authn_response.ava['EmailAddress'][0]
    first_name = authn_response.ava['FirstName'][0]
    last_name = authn_response.ava['LastName'][0]

    # Create a Django user session based on the NameID and attributes
    user = authenticate(request, name_id=name_id, email=email, first_name=first_name, last_name=last_name)
    login(request, user)

    # Redirect to the next page
    return HttpResponseRedirect('/')